import java.util.*;

public class DataStructureAdvisor {

    public enum Requirement {
        ORDERED_INSERTION, FAST_LOOKUP, LIFO_ACCESS, FIFO_ACCESS,
        KEY_VALUE_STORAGE, HIERARCHICAL
    }

    public String recommend(Set<Requirement> requirements) {
        // Return best data structure name based on requirements
        if (requirements.contains(Requirement.LIFO_ACCESS)) return "Stack";
        if (requirements.contains(Requirement.FIFO_ACCESS)) return "Queue";
        if (requirements.contains(Requirement.KEY_VALUE_STORAGE)) return "HashMap";
        if (requirements.contains(Requirement.HIERARCHICAL)) return "Tree";
        if (requirements.contains(Requirement.FAST_LOOKUP)) return "HashSet";
        if (requirements.contains(Requirement.ORDERED_INSERTION)) return "ArrayList";
        return "Array";
    }

    public Map<String, String> justification() {
        // Return map of data structure -> one-line justification
        // TODO: populate with at least Stack, Queue, HashMap, Tree, HashSet, ArrayList
        return new HashMap<>();
    }

    public static void main(String[] args) {
        DataStructureAdvisor advisor = new DataStructureAdvisor();
        System.out.println(advisor.recommend(Set.of(Requirement.LIFO_ACCESS)));
        System.out.println(advisor.recommend(Set.of(Requirement.FIFO_ACCESS)));
        System.out.println(advisor.recommend(Set.of(Requirement.KEY_VALUE_STORAGE)));
        System.out.println("Justifications: " + advisor.justification().size());
    }
}

